Export-ModuleMember -Function @(
    'Get-CurrentVersion',
    'Compare-Versions',
    'Get-BumpType',
    'Bump-Version',
    'Update-VersionFile',
    'Generate-ChangelogEntry',
    'Invoke-SemanticVersionBumper'
)

