.PARAMETER Version
Current version
.PARAMETER BumpType
Type of bump: "major", "minor", or "patch"

.OUTPUTS
Returns the new version string
#>
function Bump-Version {
    param(
        [Parameter(Mandatory = $true)]
        [string]$Version,
        [Parameter(Mandatory = $true)]
        [ValidateSet("major", "minor", "patch")]
        [string]$BumpType
    )

    $v = [System.Version]$Version
    $major = $v.Major
    $minor = $v.Minor
    $patch = $v.Build

    switch ($BumpType) {
        "major" {
            $major++
            $minor = 0
            $patch = 0
        }
        "minor" {
            $minor++
            $patch = 0
        }
        "patch" {
            $patch++
        }
    }

    return "$major.$minor.$patch"
}

